function parseFormula(formula: string): { elements: Record<string, number>; mw: number; error: string } {
  const elements: Record<string, number> = {};
  let error = "";
  const re = /([A-Z][a-z]?)(\d*)/g;
  let match;
  while ((match = re.exec(formula)) !== null) {
    const sym = match[1];
    const count = parseInt(match[2] || "1");
    if (!ELEMENTS[sym]) { error = `Unknown element: ${sym}`; break; }
    elements[sym] = (elements[sym] || 0) + count;
  }
  const mw = Object.entries(elements).reduce((sum, [el, n]) => sum + (ELEMENTS[el] || 0) * n, 0);
  return { elements, mw, error };
}

